export const getLatestTick = query({
  args: { instrumentId: v.string() },
  handler: async (ctx, { instrumentId }) => {
    const ticks = await ctx.db
      .query('tickData')
      .withIndex('by_instrument_ts', q => q.eq('instrumentId', instrumentId))
      .order('desc')
      .take(1);
    return ticks[0] ?? null;
  },
});

export const getOhlcv = query({
  args: { instrumentId: v.string(), interval: v.string(), limit: v.number() },
  handler: async (ctx, args) => {
    const identity = await ctx.auth.getUserIdentity();
    if (!identity) throw new Error('Unauthenticated');
    const access = await checkAccess(ctx, identity.subject, 'ohlcv');
    if (!access.allowed) throw new Error(access.reason);
    return await ctx.db
      .query('ohlcvData')
      .withIndex('by_instrument_interval_ts', q =>
        q.eq('instrumentId', args.instrumentId).eq('interval', args.interval)
      )
      .order('desc')
      .take(args.limit);
  },
});

export const ingestTick = mutation({
  args: {
    instrumentId: v.string(), sourceId: v.string(),
    price: v.number(), size: v.number(),
    side: v.union(v.literal('buy'), v.literal('sell'), v.literal('unknown')),
    tsUtc: v.number(),
  },
  handler: async (ctx, args) => {
    const receivedAt = Date.now();
    await ctx.db.insert('tickData', { ...args, receivedAt });
    // Update stream health
    const stream = await ctx.db.query('marketStreams')
      .withIndex('by_instrument', q => q.eq('instrumentId', args.instrumentId))
      .filter(q => q.eq(q.field('channel'), 'trades'))
      .first();
    if (stream) {
      await ctx.db.patch(stream._id, { lastMessageAt: receivedAt, status: 'active' });
    }
    // Trigger alert evaluation (async, non-blocking)
    await ctx.scheduler.runAfter(0, internal.alerts.evaluator.evaluate, {
      instrumentId: args.instrumentId, price: args.price
    });
  },
});
